input.command:
bash -c 'source /etc/turtlebot4/setup.bash; export ROS_SUPER_CLIENT=True;
echo "== PUBLISH: beep =="; timeout 15 ros2 topic pub --once /turtlebot468/cmd_audio irobot_create_msgs/msg/AudioNoteVector "{append: false, notes: [{frequency: 440, max_runtime: {sec: 0, nanosec: 500000000}}, {frequency: 880, max_runtime: {sec: 0, nanosec: 500000000}}]}" 2>&1 | tail -2;
echo "== SERVICES visible =="; timeout 10 ros2 service list 2>/dev/null | grep -E "e_stop|reset_pose|robot_power";
echo "== SERVICE CALL: param get (service machinery test) =="; timeout 15 ros2 param get /turtlebot468/turtlebot4_node wifi.interface 2>&1 | tail -1;
echo "== ACTIONS visible =="; timeout 10 ros2 action list 2>/dev/null | grep -E "dock|rotate|drive" | head -6;
echo "== odom flowing =="; timeout 10 ros2 topic hz /turtlebot468/odom --window 20 2>&1 | grep -m1 "average rate"'
